import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Bell, Shield, Moon, Sun, Lock, LogOut, ChevronRight } from 'lucide-react';

export default function Settings() {
  // State for toggles
  const [pushNotifs, setPushNotifs] = useState(true);
  const [publicProfile, setPublicProfile] = useState(true);
  const [darkMode, setDarkMode] = useState(false);

  // Effect to handle Dark Mode theme switch
  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  const Toggle = ({ enabled, setEnabled }) => (
    <button
      onClick={() => setEnabled(!enabled)}
      className={`w-12 h-6 rounded-full transition-colors relative ${
        enabled ? 'bg-teal-600' : 'bg-slate-300'
      }`}
    >
      <div
        className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${
          enabled ? 'left-7' : 'left-1'
        }`}
      />
    </button>
  );

  return (
    <motion.div 
      initial={{ opacity: 0 }} 
      animate={{ opacity: 1 }} 
      className="p-10 max-w-4xl mx-auto space-y-10 dark:text-white"
    >
      <div className="flex items-center gap-3">
        <div className="p-3 bg-teal-50 dark:bg-teal-900/30 text-teal-600 rounded-2xl">
          <Lock size={28} />
        </div>
        <div>
          <h1 className="text-4xl font-black text-slate-900 dark:text-white">Account Settings</h1>
          <p className="text-slate-500 font-medium">Manage your privacy and security preferences.</p>
        </div>
      </div>

      <div className="bg-white dark:bg-slate-900 rounded-[40px] p-10 border border-slate-50 dark:border-slate-800 shadow-sm space-y-8">
        
        {/* Dark Mode Toggle */}
        <div className="flex items-center justify-between p-4 hover:bg-slate-50 dark:hover:bg-slate-800 rounded-3xl transition-all">
          <div className="flex items-center gap-6">
            <div className="w-12 h-12 bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 rounded-2xl flex items-center justify-center">
              {darkMode ? <Sun size={24} /> : <Moon size={24} />}
            </div>
            <div>
              <h4 className="font-bold text-slate-900 dark:text-white">Appearance</h4>
              <p className="text-sm text-slate-400 font-medium">Switch between light and dark themes.</p>
            </div>
          </div>
          <Toggle enabled={darkMode} setEnabled={setDarkMode} />
        </div>

        {/* Push Notifications Toggle */}
        <div className="flex items-center justify-between p-4 hover:bg-slate-50 dark:hover:bg-slate-800 rounded-3xl transition-all">
          <div className="flex items-center gap-6">
            <div className="w-12 h-12 bg-teal-50 dark:bg-teal-900/30 text-teal-600 rounded-2xl flex items-center justify-center">
              <Bell size={24} />
            </div>
            <div>
              <h4 className="font-bold text-slate-900 dark:text-white">Push Notifications</h4>
              <p className="text-sm text-slate-400 font-medium">Receive alerts for new barter requests.</p>
            </div>
          </div>
          <Toggle enabled={pushNotifs} setEnabled={setPushNotifs} />
        </div>

        {/* Public Profile Toggle */}
        <div className="flex items-center justify-between p-4 hover:bg-slate-50 dark:hover:bg-slate-800 rounded-3xl transition-all">
          <div className="flex items-center gap-6">
            <div className="w-12 h-12 bg-blue-50 dark:bg-blue-900/30 text-blue-600 rounded-2xl flex items-center justify-center">
              <Shield size={24} />
            </div>
            <div>
              <h4 className="font-bold text-slate-900 dark:text-white">Public Profile</h4>
              <p className="text-sm text-slate-400 font-medium">Allow others to see your skills and rating.</p>
            </div>
          </div>
          <Toggle enabled={publicProfile} setEnabled={setPublicProfile} />
        </div>

        {/* Two-Factor Auth */}
        <div className="flex items-center justify-between p-4 hover:bg-slate-50 dark:hover:bg-slate-800 rounded-3xl cursor-pointer transition-all">
          <div className="flex items-center gap-6">
            <div className="w-12 h-12 bg-emerald-50 dark:bg-emerald-900/30 text-emerald-600 rounded-2xl flex items-center justify-center">
              <Shield size={24} />
            </div>
            <div>
              <h4 className="font-bold text-slate-900 dark:text-white">Two-Factor Auth</h4>
              <p className="text-sm text-slate-400 font-medium">Extra security for token transactions.</p>
            </div>
          </div>
          <ChevronRight className="text-slate-300" />
        </div>

        <button className="w-full mt-10 p-6 rounded-[32px] bg-red-50 dark:bg-red-900/10 text-red-600 font-black flex items-center justify-center gap-3 hover:bg-red-100 transition-all">
          <LogOut size={22} /> Log Out from All Devices
        </button>
        
        <p className="text-center text-[10px] font-black text-slate-300 tracking-widest uppercase">
          WERTECH V0.1.0-BETA
        </p>
      </div>
    </motion.div>
  );
}
